@keyframes slideUp { 
  0% { opacity: 0; transform: translateY(8px); }
  100% { opacity: 1; transform: translateY(0px); }
}

@keyframes slideRight { 
  0% { opacity: 0; transform: translate(-8px); }
  100% { opacity: 1; transform: translate(0px); }
}

@keyframes toastIn { 
  0% { opacity: 0; transform: translateY(12px) scale(0.96); }
  100% { opacity: 1; transform: translateY(0px) scale(1); }
}

@keyframes modalIn { 
  0% { opacity: 0; transform: scale(0.95) translateY(8px); }
  100% { opacity: 1; transform: scale(1) translateY(0px); }
}

@keyframes slideLeft { 
  0% { opacity: 0; transform: translate(20px); }
  100% { opacity: 1; transform: translate(0px); }
}

@keyframes scriptMakerCtaGlow { 
  0%, 100% { filter: saturate(); box-shadow: rgba(255, 233, 191, 0.1) 0px 1px inset, rgba(214, 174, 103, 0) 0px 0px, rgba(0, 0, 0, 0.14) 0px 10px 22px; }
  50% { filter: saturate(1.06); box-shadow: rgba(255, 233, 191, 0.18) 0px 1px inset, rgba(231, 201, 143, 0.1) 0px 0px 0px 1px, rgba(214, 174, 103, 0.24) 0px 0px 24px, rgba(0, 0, 0, 0.18) 0px 12px 28px; }
}

@keyframes bounce { 
  0%, 100% { animation-timing-function: cubic-bezier(0.8, 0, 1, 1); transform: translateY(-25%); }
  50% { animation-timing-function: cubic-bezier(0, 0, 0.2, 1); transform: none; }
}

@keyframes aurora { 
  0%, 100% { transform: translate(0px) rotate(0deg) scale(1); }
  25% { transform: translate(30px, -50px) rotate(3deg) scale(1.05); }
  50% { transform: translate(-20px, 20px) rotate(-2deg) scale(0.95); }
  75% { transform: translate(40px, 30px) rotate(4deg) scale(1.02); }
}

@keyframes aurora2 { 
  0%, 100% { transform: translate(0px) rotate(0deg) scale(1); }
  33% { transform: translate(-40px, 30px) rotate(-4deg) scale(1.08); }
  66% { transform: translate(30px, -40px) rotate(3deg) scale(0.93); }
}

@keyframes glow-pulse { 
  0%, 100% { opacity: 0.4; transform: scale(1); }
  50% { opacity: 0.8; transform: scale(1.05); }
}

@keyframes text-gradient { 
  0%, 100% { background-position: 0px center; background-size: 200% 200%; }
  50% { background-position: 100% center; background-size: 200% 200%; }
}
